  const panels = await eda.dmt_Panel.getAllPanelsInfo();
  const panelUuid = panels?.[0]?.uuid;
  const result = await eda.dmt_Panel.getPanelInfo(panelUuid);
  return {
    fixtureName,
    currentProject: currentProject?.friendlyName ?? currentProject?.name ?? currentProject?.uuid ?? null,
    result,
  };
})(eda);
